use std::io::{Error, Result};
use std::process::Command;

pub struct GitContext {
    pub working_dir: String,
}

pub trait GitStorage: Send + Sync {
    fn store(&self, session_id: &str, jsonl: &[u8], context: &GitContext) -> Result<String>;
}

pub struct NativeGitStorage;

impl GitStorage for NativeGitStorage {
    fn store(&self, session_id: &str, jsonl: &[u8], context: &GitContext) -> Result<String> {
        let dir = &context.working_dir;

        // Get remote URL
        let remote_url = git_cmd(dir, &["remote", "get-url", "origin"])?;
        let remote_url = remote_url.trim().to_string();

        // Get current branch to restore later
        let current_branch = git_cmd(dir, &["rev-parse", "--abbrev-ref", "HEAD"])
            .unwrap_or_else(|_| "main".to_string());
        let current_branch = current_branch.trim().to_string();

        // Stash current changes
        let had_changes = git_cmd(dir, &["stash"]).is_ok();

        let result = store_inner(dir, session_id, jsonl, &remote_url);

        // Always restore: checkout original branch + pop stash
        let _ = git_cmd(dir, &["checkout", &current_branch]);
        if had_changes {
            let _ = git_cmd(dir, &["stash", "pop"]);
        }

        result
    }
}

fn store_inner(dir: &str, session_id: &str, jsonl: &[u8], remote_url: &str) -> Result<String> {
    // Try to checkout opensession branch (create orphan if it doesn't exist)
    let branch_exists = git_cmd(dir, &["rev-parse", "--verify", "opensession"]).is_ok();
    if branch_exists {
        git_cmd(dir, &["checkout", "opensession"])?;
    } else {
        git_cmd(dir, &["checkout", "--orphan", "opensession"])?;
        // Remove all tracked files from index for clean orphan
        let _ = git_cmd(dir, &["rm", "-rf", "--cached", "."]);
    }

    // Write session file
    let session_dir = std::path::Path::new(dir).join(".opensession");
    std::fs::create_dir_all(&session_dir)?;
    let file_name = format!("{session_id}.hail.jsonl");
    let file_path = session_dir.join(&file_name);
    std::fs::write(&file_path, jsonl)?;

    // Add, commit, push
    let rel_path = format!(".opensession/{file_name}");
    git_cmd(dir, &["add", &rel_path])?;
    git_cmd(dir, &["commit", "-m", &format!("Add session {session_id}")])?;
    git_cmd(dir, &["push", "origin", "opensession"])?;

    // Generate raw URL
    let raw_url = generate_raw_url(remote_url, &rel_path);
    Ok(raw_url)
}

fn git_cmd(dir: &str, args: &[&str]) -> Result<String> {
    let output = Command::new("git").args(args).current_dir(dir).output()?;

    if output.status.success() {
        Ok(String::from_utf8_lossy(&output.stdout).to_string())
    } else {
        let stderr = String::from_utf8_lossy(&output.stderr);
        Err(Error::other(format!(
            "git {} failed: {}",
            args.join(" "),
            stderr
        )))
    }
}

/// Generate a raw content URL from the git remote and file path.
fn generate_raw_url(remote_url: &str, rel_path: &str) -> String {
    // Normalize remote URL to extract owner/repo
    let normalized = remote_url
        .trim_end_matches(".git")
        .replace("git@github.com:", "https://github.com/")
        .replace("git@gitlab.com:", "https://gitlab.com/");

    if normalized.contains("github.com") {
        // https://raw.githubusercontent.com/{owner}/{repo}/opensession/{path}
        let path = normalized.trim_start_matches("https://github.com/");
        format!(
            "https://raw.githubusercontent.com/{}/opensession/{}",
            path, rel_path
        )
    } else if normalized.contains("gitlab.com") {
        // https://gitlab.com/{owner}/{repo}/-/raw/opensession/{path}
        let path = normalized.trim_start_matches("https://gitlab.com/");
        format!("https://gitlab.com/{}/-/raw/opensession/{}", path, rel_path)
    } else {
        // Fallback: just use the remote URL as base
        format!("{}/raw/opensession/{}", normalized, rel_path)
    }
}

