use anyhow::Result;
use app::{App, ServerInfo, ServerStatus, StartupStatus, TeamInfo, UploadPhase, View};
use crossterm::{
    event::{self, Event, KeyEventKind},
    terminal::{disable_raw_mode, enable_raw_mode, EnterAlternateScreen, LeaveAlternateScreen},
    ExecutableCommand,
};
use opensession_local_db::git::extract_git_context;
use opensession_local_db::LocalDb;
use ratatui::prelude::*;
use std::io::stdout;
use std::path::PathBuf;
use std::sync::Arc;
use std::time::Duration;

fn main() -> Result<()> {
    let args: Vec<String> = std::env::args().collect();

    let sessions = if args.len() > 1 {
        // Load from explicit file paths
        load_from_paths(&args[1..])
    } else {
        // Auto-discover local sessions
        load_sessions()
    };

    let mut app = App::new(sessions);

    // ── Load full daemon config ──────────────────────────────────────
    let daemon_config = config::load_daemon_config();
    let config_exists = config::config_dir()
        .map(|d| d.join("daemon.toml").exists())
        .unwrap_or(false);

    // Build server info from daemon config
    app.server_info = build_server_info(&daemon_config);
    app.team_id = if daemon_config.identity.team_id.is_empty() {
        None
    } else {
        Some(daemon_config.identity.team_id.clone())
    };
    app.daemon_config = daemon_config;
    app.connection_ctx = App::derive_connection_ctx(&app.daemon_config);

    // ── Build startup status ─────────────────────────────────────────
    let mut status = StartupStatus {
        sessions_cached: 0,
        repos_detected: 0,
        daemon_pid: config::daemon_pid(),
        config_exists,
    };

    // ── Open local DB and cache sessions ─────────────────────────────
    if let Ok(db) = LocalDb::open() {
        let db = Arc::new(db);
        // Cache parsed sessions into the local DB
        cache_sessions_to_db(&db, &app.sessions);
        status.sessions_cached = app.sessions.len();
        // Load repo list for view cycling
        app.repos = db.list_repos().unwrap_or_default();
        status.repos_detected = app.repos.len();
        app.db = Some(db);
    }

    app.startup_status = status;

    // ── If config needs setup, start in Setup view ───────────────────
    if config::needs_setup(&app.daemon_config) {
        app.view = View::Setup;
        app.settings_index = 0;
    }

    // If targeting a local Docker server, do a health check
    if let Some(ref mut info) = app.server_info {
        if is_local_url(&info.url) {
            let url = info.url.clone();
            let rt = tokio::runtime::Runtime::new()?;
            info.status = rt.block_on(check_health(&url));
        }
    }

    // Terminal setup
    enable_raw_mode()?;
    stdout().execute(EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(stdout());
    let mut terminal = Terminal::new(backend)?;

    // Main loop
    let result = run(&mut terminal, &mut app);

    // Restore terminal
    disable_raw_mode()?;
    stdout().execute(LeaveAlternateScreen)?;

    result
}

fn is_local_url(url: &str) -> bool {
    let lower = url.to_lowercase();
    lower.contains("localhost")
        || lower.contains("127.0.0.1")
        || lower.contains("192.168.")
        || lower.contains("10.")
        || lower.contains("172.16.")
}

fn build_server_info(config: &config::DaemonConfig) -> Option<ServerInfo> {
    if config.server.url.is_empty() {
        return None;
    }

    // Try to read last upload time from state.json (legacy)
    let home = std::env::var("HOME")
        .or_else(|_| std::env::var("USERPROFILE"))
        .unwrap_or_default();
    let state_path = PathBuf::from(&home)
        .join(".config")
        .join("opensession")
        .join("state.json");

    let last_upload = std::fs::read_to_string(&state_path)
        .ok()
        .and_then(|s| serde_json::from_str::<serde_json::Value>(&s).ok())
        .and_then(|v| {
            v.get("uploaded")?
                .as_object()?
                .values()
                .filter_map(|v| v.as_str().map(String::from))
                .max()
        });

    Some(ServerInfo {
        url: config.server.url.clone(),
        status: ServerStatus::Unknown,
        last_upload,
    })
}

async fn check_health(server_url: &str) -> ServerStatus {
    let url = format!("{}/api/health", server_url.trim_end_matches('/'));
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(3))
        .build()
        .unwrap_or_default();

    match client.get(&url).send().await {
        Ok(resp) if resp.status().is_success() => {
            if let Ok(body) = resp.json::<serde_json::Value>().await {
                let version = body
                    .get("version")
                    .and_then(|v| v.as_str())
                    .unwrap_or("unknown")
                    .to_string();
                ServerStatus::Online(version)
            } else {
                ServerStatus::Online("unknown".to_string())
            }
        }
        _ => ServerStatus::Offline,
    }
}

/// Cache parsed sessions into the local DB with git context.
fn cache_sessions_to_db(db: &LocalDb, sessions: &[opensession_core::trace::Session]) {
    for session in sessions {
        // Determine source path (best-effort: use session_id as key)
        let source = session.session_id.clone();

        // Extract git context from working directory
        let cwd = session
            .context
            .attributes
            .get("cwd")
            .or_else(|| session.context.attributes.get("working_directory"))
            .and_then(|v| v.as_str().map(String::from));
        let git = cwd.as_deref().map(extract_git_context).unwrap_or_default();

        let _ = db.upsert_local_session(session, &source, &git);
    }
}

// ── Login async ─────────────────────────────────────────────────────────────

async fn perform_login(
    server_url: &str,
    email: &str,
    [REDACTED_CREDENTIAL]
) -> Result<(String, String), String> {
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(10))
        .build()
        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;

    let base = server_url.trim_end_matches('/');

    // Step 1: POST /api/auth/login → access_token
    let login_body = opensession_api_types::LoginRequest {
        email: email.to_string(),
        [REDACTED_CREDENTIAL]
    };

    let resp = client
        .post(format!("{base}/api/auth/login"))
        .json(&login_body)
        .send()
        .await
        .map_err(|e| format!("Failed to connect: {e}"))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(format!("Error {status}: {body}"));
    }

    let token_resp: opensession_api_types::AuthTokenResponse = resp
        .json()
        .await
        .map_err(|e| format!("Failed to parse login response: {e}"))?;

    // Step 2: GET /api/auth/me → api_key, nickname
    let me_resp = client
        .get(format!("{base}/api/auth/me"))
        .bearer_auth(&token_resp.access_token)
        .send()
        .await
        .map_err(|e| format!("Failed to fetch user settings: {e}"))?;

    if !me_resp.status().is_success() {
        let status = me_resp.status();
        let body = me_resp.text().await.unwrap_or_default();
        return Err(format!("Error fetching profile {status}: {body}"));
    }

    let user: opensession_api_types::UserSettingsResponse = me_resp
        .json()
        .await
        .map_err(|e| format!("Failed to parse user settings: {e}"))?;

    Ok((user.api_key, user.nickname))
}

// ── Fetch teams async ───────────────────────────────────────────────────────

async fn fetch_teams(server_url: &str, [REDACTED_CREDENTIAL] -> Result<Vec<TeamInfo>, String> {
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(10))
        .build()
        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;

    let base = server_url.trim_end_matches('/');

    let resp = client
        .get(format!("{base}/api/teams"))
        .bearer_auth(api_key)
        .send()
        .await
        .map_err(|e| format!("Failed to fetch teams: {e}"))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(format!("Error {status}: {body}"));
    }

    let list: opensession_api_types::ListTeamsResponse = resp
        .json()
        .await
        .map_err(|e| format!("Failed to parse teams: {e}"))?;

    // Build team list: Personal first, then actual teams
    let mut teams = vec![TeamInfo {
        id: String::new(),
        name: "Personal (Public)".to_string(),
        is_personal: true,
    }];

    for t in list.teams {
        teams.push(TeamInfo {
            id: t.id,
            name: t.name,
            is_personal: false,
        });
    }

    Ok(teams)
}

// ── Upload session async ────────────────────────────────────────────────────

async fn upload_session(
    server_url: &str,
    [REDACTED_CREDENTIAL]
    session: &opensession_core::trace::Session,
    team_id: Option<String>,
    body_url: Option<String>,
) -> Result<String, String> {
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(30))
        .build()
        .map_err(|e| format!("Failed to create HTTP client: {e}"))?;

    let base = server_url.trim_end_matches('/');

    let session_value =
        serde_json::to_value(session).map_err(|e| format!("Failed to serialize session: {e}"))?;

    let upload_req = opensession_api_types::UploadRequest {
        session: session_value,
        team_id,
        body_url,
        linked_session_ids: None,
    };

    let resp = client
        .post(format!("{base}/api/sessions"))
        .bearer_auth(api_key)
        .json(&upload_req)
        .send()
        .await
        .map_err(|e| format!("Failed to upload: {e}"))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(format!("Error {status}: {body}"));
    }

    let upload_resp: opensession_api_types::UploadResponse = resp
        .json()
        .await
        .map_err(|e| format!("Failed to parse upload response: {e}"))?;

    Ok(upload_resp.url)
}

fn run(terminal: &mut Terminal<CrosstermBackend<std::io::Stdout>>, app: &mut App) -> Result<()> {
    let rt = tokio::runtime::Runtime::new()?;

    loop {
        // ── Handle async operations between frames ──────────────────
        // Login
        if app.login_state.loading {
            let server_url = app.daemon_config.server.url.clone();
            let email = app.login_state.email.clone();
            let password = app.login_state.password.clone();

            match rt.block_on(perform_login(&server_url, &email, &password)) {
                Ok((api_key, nickname)) => {
                    app.daemon_config.server.api_key = api_key;
                    app.daemon_config.identity.nickname = nickname;
                    app.config_dirty = true;
                    app.save_config();
                    app.connection_ctx = App::derive_connection_ctx(&app.daemon_config);
                    app.login_state.loading = false;
                    app.login_state.status = Some("Login successful!".to_string());
                    app.view = View::SessionList;
                }
                Err(e) => {
                    app.login_state.loading = false;
                    app.login_state.status = Some(format!("Error: {e}"));
                }
            }
        }

        // Fetch teams for upload popup
        if let Some(ref popup) = app.upload_popup {
            if matches!(popup.phase, UploadPhase::FetchingTeams) {
                let server_url = app.daemon_config.server.url.clone();
                let api_key = app.daemon_config.server.api_key.clone();

                match rt.block_on(fetch_teams(&server_url, &api_key)) {
                    Ok(teams) => {
                        if let Some(ref mut popup) = app.upload_popup {
                            popup.teams = teams;
                            popup.phase = UploadPhase::SelectTeam;
                            popup.status = None;
                        }
                    }
                    Err(e) => {
                        if let Some(ref mut popup) = app.upload_popup {
                            popup.status = Some(format!("Error: {e}"));
                            popup.phase = UploadPhase::Done;
                        }
                    }
                }
            }
        }

        // Upload session
        if let Some(ref popup) = app.upload_popup {
            if matches!(popup.phase, UploadPhase::Uploading) {
                let server_url = app.daemon_config.server.url.clone();
                let api_key = app.daemon_config.server.api_key.clone();

                let team_id = popup.teams.get(popup.selected).and_then(|t| {
                    if t.is_personal {
                        None
                    } else {
                        Some(t.id.clone())
                    }
                });

                // Get selected session
                let session_clone = app.selected_session().cloned();

                if let Some(session) = session_clone {
                    let is_personal = popup
                        .teams
                        .get(popup.selected)
                        .map(|t| t.is_personal)
                        .unwrap_or(false);

                    // For personal sessions, try git storage
                    let body_url = if is_personal {
                        try_git_store(&session, &app.daemon_config)
                    } else {
                        None
                    };

                    match rt.block_on(upload_session(
                        &server_url,
                        &api_key,
                        &session,
                        team_id,
                        body_url,
                    )) {
                        Ok(url) => {
                            if let Some(ref mut popup) = app.upload_popup {
                                popup.status = Some(format!("Uploaded: {url}"));
                                popup.phase = UploadPhase::Done;
                            }
                        }
                        Err(e) => {
                            if let Some(ref mut popup) = app.upload_popup {
                                popup.status = Some(format!("Error: {e}"));
                                popup.phase = UploadPhase::Done;
                            }
                        }
                    }
                } else if let Some(ref mut popup) = app.upload_popup {
                    popup.status = Some("No session selected".to_string());
                    popup.phase = UploadPhase::Done;
                }
            }
        }

        terminal.draw(|frame| ui::render(frame, app))?;

        if event::poll(Duration::from_millis(100))? {
            if let Event::Key(key) = event::read()? {
                if key.kind != KeyEventKind::Press {
                    continue;
                }
                if app.handle_key(key.code) {
                    break;
                }
            }
        }
    }
    Ok(())
}

/// Try to store a session via git and return the body_url.
fn try_git_store(
    session: &opensession_core::trace::Session,
    config: &config::DaemonConfig,
) -> Option<String> {
    if !matches!(config.git_storage.method, config::GitStorageMethod::Native) {
        return None;
    }

    // Get working directory from session context
    let cwd = session
        .context
        .attributes
        .get("cwd")
        .or_else(|| session.context.attributes.get("working_directory"))
        .and_then(|v| v.as_str())?;

    let jsonl = session.to_jsonl().ok()?;

    let git_ctx = opensession_core::git_storage::GitContext {
        working_dir: cwd.to_string(),
    };
    let storage = opensession_core::git_storage::NativeGitStorage;
    opensession_core::git_storage::GitStorage::store(
        &storage,
        &session.session_id,
        jsonl.as_bytes(),
        &git_ctx,
    )
    .ok()
}

/// Load sessions from explicit file paths passed as CLI args.
fn load_from_paths(args: &[String]) -> Vec<opensession_core::trace::Session> {
    let parsers = opensession_parsers::all_parsers();
    let mut sessions = Vec::new();

    for arg in args {
        let path = PathBuf::from(arg);
        if !path.exists() {
            eprintln!("Warning: file not found: {}", path.display());
            continue;
        }
        if let Some(parser) = parsers.iter().find(|p| p.can_parse(&path)) {
            match parser.parse(&path) {
                Ok(session) => sessions.push(session),
                Err(e) => eprintln!("Warning: failed to parse {}: {}", path.display(), e),
            }
        } else {
            eprintln!("Warning: no parser for {}", path.display());
        }
    }

    sessions.sort_by(|a, b| b.context.created_at.cmp(&a.context.created_at));
    sessions
}

/// Auto-discover sessions from known local paths.
fn load_sessions() -> Vec<opensession_core::trace::Session> {
    let locations = opensession_parsers::discover::discover_sessions();
    let parsers = opensession_parsers::all_parsers();
    let mut sessions = Vec::new();

    for location in &locations {
        for path in &location.paths {
            // Skip subagent session files
            let path_str = path.to_string_lossy();
            if path_str.contains("/subagents/") || path_str.contains("\\subagents\\") {
                continue;
            }
            if let Some(fname) = path.file_name().and_then(|f| f.to_str()) {
                if fname.starts_with("agent-") {
                    continue;
                }
            }

            if let Some(parser) = parsers.iter().find(|p| p.can_parse(path)) {
                if let Ok(session) = parser.parse(path) {
                    // Skip empty sessions (0 events usually means parse was incomplete)
                    if session.stats.event_count > 0 {
                        sessions.push(session);
                    }
                }
            }
        }
    }

    sessions.sort_by(|a, b| b.context.created_at.cmp(&a.context.created_at));
    sessions
}

